let result = $json.result || {};
if (typeof result === 'string') { try { result = JSON.parse(result); } catch { result = {}; } }
return [{ json: { ...result, chat_id: String($json.chat_id || '') } }];

if ($json.route !== 'direct') return [];
const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const status = String($json.status || 'help');
let reply = '';
if (status === 'recent') {
  const items = Array.isArray($json.items) ? $json.items : [];
  reply = items.length ? `<b>Останні записи</b>

${items.map((item) => `${item.is_archived ? '📦' : '•'} <code>${e(item.short_id)}</code> — ${e(item.title)}
  ${e(item.content_type)} · ${e(item.status)}`).join('\n\n')}` : 'Пам’ять поки порожня.';
} else if (status === 'show') {
  const item = $json.item || {};
  const tags = Array.isArray(item.tags) ? item.tags : [];
  const files = Array.isArray(item.attachments) ? item.attachments : [];
  reply = `<b>${e(item.title)}</b>
<code>${e(item.short_id)}</code>${item.is_archived ? ' · 📦 архів' : ''}

${e(item.summary)}

<b>Проєкт:</b> ${e(item.project)}
<b>Категорія:</b> ${e(item.category)}
<b>Тип:</b> ${e(item.item_type)}
<b>Пріоритет:</b> ${e(item.priority)}
<b>Статус:</b> ${e(item.status)}${tags.length ? `
<b>Теги:</b> ${tags.map(e).join(', ')}` : ''}${files.length ? `
<b>Файли:</b> ${files.map(e).join(', ')}` : ''}${item.source_url ? `
<b>Джерело:</b> ${e(item.source_url)}` : ''}`;
} else if (status === 'archived') {
  reply = `📦 Запис <code>${e($json.short_id)}</code> переміщено в архів.
${e($json.title)}`;
} else if (status === 'delete_confirmation') {
  reply = `⚠️ <b>Підтвердження видалення</b>

<code>${e($json.short_id)}</code> — ${e($json.title)}

Це видалить запис із PostgreSQL, його вектори з Qdrant і окремий файл із B2, якщо на нього немає інших посилань.

Підтвердити протягом ${Number($json.expires_minutes || 10)} хвилин:
<code>/confirm ${e($json.token)}</code>

Скасувати:
<code>/cancel ${e($json.token)}</code>`;
} else if (status === 'cancelled') {
  reply = '✅ Видалення скасовано.';
} else if (status === 'unauthorized') {
  reply = '⛔ Цей Telegram-користувач не має доступу до пам’яті.';
} else if (status === 'token_required') {
  reply = 'Вкажіть код підтвердження: <code>/confirm КОД</code> або <code>/cancel КОД</code>.';
} else if (status === 'action_not_found') {
  reply = 'Код підтвердження не знайдено.';
} else if (status === 'action_not_pending') {
  reply = 'Ця дія вже виконана, скасована або її код прострочений.';
} else if (status === 'item_id_required') {
  reply = 'Вкажіть щонайменше 6 символів ID запису. Отримати ID: <code>/recent</code>.';
} else if (status === 'item_not_found') {
  reply = 'Запис із таким ID не знайдено.';
} else if (status === 'item_id_ambiguous') {
  reply = 'Цей фрагмент ID неоднозначний — вкажіть більше символів.';
} else {
  reply = `<b>Керування пам’яттю</b>

<code>/recent</code> — останні 10 записів
<code>/show ID</code> — деталі запису
<code>/archive ID</code> — перемістити в архів
<code>/reindex ID</code> — перебудувати RAG-індекс
<code>/delete ID</code> — підготувати безпечне видалення
<code>/confirm КОД</code> — підтвердити видалення
<code>/cancel КОД</code> — скасувати видалення`;
}
return [{ json: { chat_id: $json.chat_id, reply } }];

const source = $('Prepare Safe Deletion').first().json;
let objects = source.objects_to_delete || [];
if (typeof objects === 'string') { try { objects = JSON.parse(objects); } catch { objects = []; } }
if (!Array.isArray(objects) || objects.length === 0) return [{ json: { ...source, skip_b2: true } }];
return objects.map((object) => ({ json: { ...source, skip_b2: false, storage_bucket: object.bucket, object_key: object.key } }));

const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const reply = $json.deleted ? `🗑 Запис <code>${e($json.short_id)}</code> видалено.
${e($json.title)}

PostgreSQL, Qdrant і незадубльований оригінал B2 очищено.` : 'Дію вже завершено або запис був видалений раніше.';
return [{ json: { chat_id: $json.chat_id, reply } }];

const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
return [{ json: { chat_id: $json.chat_id, reply: `🔄 Переіндексацію запущено для <code>${e($json.short_id)}</code>.
${e($json.title)}

Старі фрагменти: ${Number($json.old_chunks_removed || 0)}. Новий RAG-індекс створюється у фоні.` } }];
